import api from './api';

export default {
  /**
   * Get current user profile
   * @returns {Promise} Promise containing the user's profile data
   */
  getUserProfile() {
    return api.get('/user/me');
  },

  /**
   * Update user profile
   * @param {Object} profileData - The profile data to update
   * @returns {Promise} Promise containing the updated profile
   */
  updateProfile(profileData) {
    return api.put('/user/profile', profileData);
  },

  /**
   * Change user password
   * @param {Object} passwordData - Object containing old and new passwords
   * @returns {Promise} Promise containing the result of the operation
   */
  changePassword(passwordData) {
    return api.post('/user/change-password', passwordData);
  },

  /**
   * Get user statistics
   * @returns {Promise} Promise containing the user's statistics
   */
  getUserStats() {
    return api.get('/user/stats');
  },

  /**
   * Get novels uploaded by the current user
   * @returns {Promise} Promise containing the user's novels
   */
  getUserNovels() {
    // 从localStorage获取当前用户ID
    const userStr = localStorage.getItem('user');
    if (!userStr) {
      console.warn('获取用户小说：没有登录用户信息');
      return Promise.reject(new Error('未登录'));
    }

    try {
      const userData = JSON.parse(userStr);
      const userId = userData.id;

      if (!userId) {
        console.warn('获取用户小说：用户数据中没有ID');
        return Promise.reject(new Error('用户ID不存在'));
      }

      console.log('获取用户小说：使用用户ID', userId);
      return api.get('/novels', { params: { userId } });
    } catch (e) {
      console.error('解析用户数据失败:', e);
      return Promise.reject(e);
    }
  }
};
